const original = $('Preparar email para IA').item.json;
const content = $json.choices?.[0]?.message?.content || '{}';

let ia;
try {
  ia = JSON.parse(content);
} catch (error) {
  ia = {
    prioridade: 'MEDIA',
    categoria: 'OUTRO',
    cliente_ou_projeto: 'NÃO IDENTIFICADO',
    resumo: content || 'Não foi possível gerar resumo.',
    pendencias: [],
    risco_ou_alerta: 'A IA não retornou JSON válido.',
    resposta_sugerida: '',
    precisa_responder: true,
    prazo_sugerido: 'Hoje'
  };
}

const pendenciasTexto = Array.isArray(ia.pendencias) && ia.pendencias.length
  ? ia.pendencias.map(p => `• ${p}`).join('\n')
  : '• Nenhuma pendência clara identificada.';

const corPrioridade = ia.prioridade === 'ALTA' ? '🔴' : ia.prioridade === 'MEDIA' ? '🟡' : '🟢';

const mensagemTeams = `🤖 **Secretária IA - Novo e-mail**

${corPrioridade} **Prioridade:** ${ia.prioridade || 'MEDIA'}
📂 **Categoria:** ${ia.categoria || 'OUTRO'}
👤 **Cliente/Projeto:** ${ia.cliente_ou_projeto || 'NÃO IDENTIFICADO'}
⏰ **Prazo sugerido:** ${ia.prazo_sugerido || 'Hoje'}

📧 **De:** ${original.from}
📌 **Assunto:** ${original.subject}

📝 **Resumo:**
${ia.resumo || 'Sem resumo.'}

✅ **Pendências:**
${pendenciasTexto}

⚠️ **Alerta:**
${ia.risco_ou_alerta || 'Nenhum alerta importante.'}

✍️ **Resposta sugerida:**
${ia.resposta_sugerida || 'Nenhuma resposta sugerida.'}

_Obs.: nada foi enviado ao cliente. Apenas análise para aprovação._`;

return [{
  json: {
    ...original,
    ...ia,
    mensagemTeams,
    TEAMS_WEBHOOK_URL: original.TEAMS_WEBHOOK_URL
  }
}];

return [
  {
    json: {
      adaptiveCard: {
        attachments: [
          {
            contentType: "application/vnd.microsoft.card.adaptive",
            content: {
              type: "AdaptiveCard",
              version: "1.4",
              body: [
                {
                  type: "TextBlock",
                  text: $json.mensagemTeams,
                  wrap: true
                }
              ]
            }
          }
        ]
      }
    }
  }
];
